// src/components/SlaveConsole.jsx
import React, { useEffect, useState, useRef } from "react";

let ipcRenderer;
try {
    ipcRenderer = window.require("electron").ipcRenderer;
} catch (e) {
    console.warn("Running outside Electron, ipcRenderer not available");
}

const MAX_ROWS = 10000;

/**
 * Merge new log lines into existing rows, collapsing tqdm-style progress lines
 * so each progress bar appears as a single line that keeps updating.
 */
function mergeLinesWithTqdm(prevRows, newLines) {
    const rows = [...prevRows];

    for (let raw of newLines || []) {
        if (!raw) continue;
        const line = raw.replace(/\r/g, "").trimEnd();
        if (!line) continue;

        // Heuristic for tqdm:
        // e.g. "Slave 1000 Progress:  63%|█████████... 619/974 [xx:xx<xx:xx, 1.23it/s]"
        const hasProgress = line.includes("Progress:");
        const hasPercentBar = line.includes("%|");

        if (hasProgress && hasPercentBar) {
            // Key = stable prefix up to "Progress:" (no %)
            const progressIdx = line.indexOf("Progress:");
            const key = line.substring(0, progressIdx + "Progress:".length).trim();

            // Find last row for this key
            let idx = -1;
            for (let i = rows.length - 1; i >= 0; i--) {
                const r = rows[i];
                if (r.type === "tqdm" && r.key === key) {
                    idx = i;
                    break;
                }
            }

            if (idx >= 0) {
                // Update existing tqdm row
                rows[idx] = { ...rows[idx], text: line };
            } else {
                // First time this progress bar appears
                rows.push({ type: "tqdm", key, text: line });
            }
        } else {
            // Normal line, just append
            rows.push({ type: "normal", key: null, text: line });
        }
    }

    // Keep only the last MAX_ROWS rows
    if (rows.length > MAX_ROWS) {
        return rows.slice(rows.length - MAX_ROWS);
    }
    return rows;
}

const SlaveConsole = () => {
    const [rows, setRows] = useState([]);
    const bottomRef = useRef(null);

    useEffect(() => {
        if (!ipcRenderer) return;

        let handler;

        const setup = async () => {
            try {
                // 1) Load existing log from file (history)
                const initialLines = await ipcRenderer.invoke("get-slave-log");
                if (Array.isArray(initialLines)) {
                    setRows((prev) => mergeLinesWithTqdm(prev, initialLines));
                }
            } catch (err) {
                console.error("[SlaveConsole] get-slave-log failed:", err);
            }

            // 2) Subscribe to new streamed lines
            handler = (_event, newLines) => {
                setRows((prev) => mergeLinesWithTqdm(prev, newLines));
            };

            ipcRenderer.on("slave-log-lines", handler);
        };

        setup();

        return () => {
            if (handler) {
                ipcRenderer.removeListener("slave-log-lines", handler);
            }
        };
    }, []);

    useEffect(() => {
        if (bottomRef.current) {
            bottomRef.current.scrollIntoView({ behavior: "smooth" });
        }
    }, [rows]);

    return (
        <div
            style={{
                backgroundColor: "#000",
                color: "#0f0",
                borderRadius: "12px",
                padding: "16px",
                width: "100%",
                height: "100%",
                boxSizing: "border-box",
                overflowY: "auto",
                fontFamily: "monospace",
                fontSize: "0.9rem",
            }}
        >
            {rows.map((row, idx) => (
                <div key={idx}>{row.text}</div>
            ))}
            <div ref={bottomRef} />
        </div>
    );
};

export default SlaveConsole;
